-- Ejecutar este script en MySQL Workbench
CREATE DATABASE  IF NOT EXISTS `bd_peliculas`
USE `bd_peliculas`;

DROP TABLE IF EXISTS `peliculas`;

CREATE TABLE `peliculas` (
  `id` int NOT NULL AUTO_INCREMENT,
  `titulo` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `director` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `genero` varchar(120) COLLATE utf8mb4_unicode_ci NOT NULL,
  `anio` int NOT NULL,
  `duracion_min` int NOT NULL,
  `clasificacion` enum('G','PG','PG-13','R','NC-17') COLLATE utf8mb4_unicode_ci NOT NULL,
  `estado` enum('disponible','no disponible') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'disponible',
  `sinopsis` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `poster_data` longtext COLLATE utf8mb4_unicode_ci,
  `poster_mime_type` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=21 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

LOCK TABLES `peliculas` WRITE;

INSERT INTO `peliculas` VALUES (9,'Blade Runner 2049','Denis Villeneuve','Ciencia ficción',2017,163,'R','disponible','Treinta años después de la original, el oficial K (Ryan Gosling), un nuevo Blade Runner replicante, descubre un secreto largamente enterrado que amenaza con destruir lo poco que queda de la sociedad. Su búsqueda por la verdad lo lleva a encontrar a Rick Deckard (Harrison Ford), desaparecido hace décadas, cuestionando la humanidad y la realidad','/img/bladerunner-1773090438883.jpg',NULL,'2026-03-09 20:04:06','2026-03-09 21:08:22'),(10,'Interstellar','Christopher Nolan','Ciencia ficción',2014,169,'PG-13','no disponible','En un futuro distópico donde la Tierra agoniza por la falta de recursos, un grupo de astronautas liderado por el expiloto Cooper viaja a través de un agujero de gusano cerca de Saturno. Su misión es encontrar un nuevo hogar habitable en otra galaxia para salvar a la humanidad, explorando la relatividad del tiempo y la física cuántica, mientras Cooper enfrenta la dolorosa separación de sus hijos.','/img/interstellar-2014-advance-original-film-art-682852f2-23f6-46de-a1db-4029d5b6f0b4-5000x-1773090623118.jpg',NULL,'2026-03-09 20:05:11','2026-03-09 21:10:23'),(11,'Scary Movie','Keenen Ivory Wayans','Comedia',2000,88,'R','no disponible','Un grupo de adolescentes, liderado por Cindy Campbell, es acechado por un asesino con máscara tras ocultar un secreto mortal, destacando por su humor absurdo y satírico.','/img/scarymovie-1773090748231.jpg',NULL,'2026-03-09 20:06:58','2026-03-09 21:12:28'),(12,'Batman: El caballero de la noche','Christopher Nolan','Acción',2008,152,'PG-13','disponible','Batman (Christian Bale) intensifica su lucha contra el crimen organizado en Gotham junto al teniente Gordon y el fiscal Harvey Dent. Sin embargo, la anarquía desatada por el Joker (Heath Ledger), un psicópata criminal, sume a la ciudad en el caos, obligando a Batman a enfrentar sus mayores pruebas físicas y psicológicas.','/img/the-dark-knight-rises-teaser-poster-1773090850312.png',NULL,'2026-03-09 21:14:10','2026-03-09 21:14:10'),(13,'Memento','Christopher Nolan','Drama psicológico',2000,113,'R','disponible','Leonard, con amnesia anterógrada (incapaz de crear nuevos recuerdos), busca al asesino de su esposa usando tatuajes, fotos y notas. La estructura confusa refleja su desorientación mental, explorando la fragilidad de la memoria y la identidad.','/img/mv5bmgq3y2q4njktn2e4ny00y2q2ltlizdutztninjrhy2i0ngiyxkeyxkfqcgc-v1-fmjpg-ux1000-1773091014336.jpg',NULL,'2026-03-09 21:16:54','2026-03-09 21:16:54'),(14,'Transformers: La era de la extinción','Michael Bay','Ciencia ficción',2014,165,'PG-13','disponible','Cuatro años después de la batalla de Chicago, los Transformers son perseguidos por la CIA y un cazarrecompensas alienígena. Un inventor (Mark Wahlberg) encuentra a un dañado Optimus Prime, uniendo fuerzas para luchar contra humanos corruptos y una nueva amenaza tecnológica que busca crear sus propios Transformers, forzando el regreso de los Autobots.','/img/transformers-age-1773091343124.jpg',NULL,'2026-03-09 21:22:23','2026-03-09 21:22:23'),(15,'Eso (It)','Andrés Muschietti','Terror',2017,135,'NC-17','no disponible','En el verano de 1989, siete niños marginados en Derry, Maine (el \"Club de los Perdedores\"), enfrentan sus peores temores al luchar contra Pennywise, un sádico payaso asesino que cambia de forma y devora niños cada 27 años. Tras la desaparición del hermano de Bill, el grupo decide unirse para destruir a esta entidad maligna que acecha en las alcantarillas, superando sus miedos personales y el acoso escolar.','/img/it-2017-advance-original-film-art-5000x-1773091572629.png',NULL,'2026-03-09 21:26:12','2026-03-09 21:26:12'),(16,'Al filo del mañana','Doug Liman','Acción',2014,113,'NC-17','no disponible','En un futuro invadido por alienígenas invencibles, el oficial sin experiencia William Cage (Tom Cruise) muere en combate, pero entra en un bucle temporal que le obliga a revivir la misma batalla una y otra vez. Con cada muerte, Cage se vuelve más habilidoso, aliándose con la guerrera Rita Vrataski (Emily Blunt) para encontrar la forma de vencer al enemigo y salvar la humanidad. ','/img/al-filo-del-manana-cartel-5477-1773091839464.jpg',NULL,'2026-03-09 21:30:39','2026-03-09 21:30:39'),(17,'Toy Story','John Lasseter','Animación',1995,81,'G','disponible','Narra la rivalidad entre Woody, un vaquero de trapo y juguete favorito del niño Andy, y Buzz Lightyear, una moderna figura de acción espacial que llega como regalo nuevo. Tras perderse y enfrentar al vecino destructor de juguetes, ambos deben superar sus celos y cooperar para regresar a casa, forjando una gran amistad','/img/71apomhl5sl-ac-uf894-1000-ql80-1773091984809.jpg',NULL,'2026-03-09 21:33:04','2026-03-09 21:33:04'),(18,'El pianista','Roman Polanski','Drama',2002,143,'R','disponible','Narra la historia real de Wladyslaw Szpilman, un brillante músico judío polaco que lucha por sobrevivir al horror de la ocupación nazi en Varsovia durante la Segunda Guerra Mundial. Tras ser separado de su familia y confinado al gueto, Szpilman logra escapar y vive escondido entre las ruinas de la ciudad, pasando hambre y miseria.','/img/images-2-1773092213262.png',NULL,'2026-03-09 21:36:53','2026-03-09 21:36:53'),(19,'El cadáver de la novia','Tim Burton','Animación',2005,76,'PG','disponible','Narra la historia de Víctor, un joven nervioso que, al practicar sus votos matrimoniales en el bosque, se casa accidentalmente con Emily, una novia cadáver que lo arrastra al mundo de los muertos. Atrapado entre su prometida viva, Victoria, y su esposa espectral, Víctor debe resolver el conflicto en un cuento sobre amor, vida y muerte.','/img/001-1773092477580.jpg',NULL,'2026-03-09 21:41:17','2026-03-09 21:41:17'),(20,'Las Crónicas de Narnia: El león, la bruja y el armario','Andrew Adamson','Fantasía',2005,143,'PG','disponible','Durante la Segunda Guerra Mundial, cuatro hermanos (Peter, Susan, Edmund y Lucy Pevensie) descubren un armario mágico que sirve de puerta a Narnia, un mundo congelado en un invierno eterno por la malvada Bruja Blanca. Junto al león Aslan, luchan para romper el hechizo, liberar el reino y cumplir una antigua profecía. ','/img/20065582-1773092667110.jpg',NULL,'2026-03-09 21:44:27','2026-03-09 21:44:27');

